mapper.select:
SELECT o.orderId, o.orderNO, o.userId, o.productId, o.paymentAmount, o.status, o.payStatus, o.receiverName, o.receiverPhone, o.receiverAddress, o.createTime, o.deletedAt, p.productId AS p_productId, p.userId AS p_userId, p.productNo AS p_productNo, p.productName AS p_productName, p.productPhoto AS p_productPhoto, p.productType AS p_productType, p.productPrice AS p_productPrice, p.productState AS p_productState, p.productInfo AS p_productInfo, p.createTime AS p_createTime, p.updateTime AS p_updateTime, u.userId AS u_userId, u.userCode AS u_userCode, u.avatar AS u_avatar, u.userName AS u_userName, u.passWord AS u_passWord, u.onlineUsername AS u_onlineUsername, u.email AS u_email, u.telephoneNumber AS u_telephoneNumber, u.status AS u_status, u.role AS u_role, u.balance AS u_balance, u.createTime AS u_createTime, u.updateTime AS u_updateTime, pu.userId AS pu_userId, pu.userCode AS pu_userCode, pu.avatar AS pu_avatar, pu.userName AS pu_userName, pu.passWord AS pu_passWord, pu.onlineUsername AS pu_onlineUsername, pu.email AS pu_email, pu.telephoneNumber AS pu_telephoneNumber, pu.status AS pu_status, pu.role AS pu_role, pu.balance AS pu_balance, pu.createTime AS pu_createTime, pu.updateTime AS pu_updateTime FROM `order` o LEFT JOIN product p ON o.productId = p.productId LEFT JOIN user u ON o.userId = u.userId LEFT JOIN user pu ON p.userId = pu.userId WHERE o.deletedAt = 1
AND p.productType = #{productType}
AND p.productName LIKE CONCAT('%', #{productName}, '%')
